import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/multi-sample-player.png",m=JSON.parse('{"title":"Multi Sample","description":"","frontmatter":{},"headers":[],"relativePath":"modules/multi-sample-player.md","filePath":"modules/multi-sample-player.md"}'),d={name:"modules/multi-sample-player.md"};function i(l,t,n,p,c,u){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="multi-sample" tabindex="-1">Multi Sample <a class="header-anchor" href="#multi-sample" aria-label="Permalink to &quot;Multi Sample&quot;">​</a></h1><p><strong>Category:</strong> Other</p><p>16-slot sample bank organized as 4 banks of 4 slots. Loads ms_01.wav through ms_16.wav from an SD card folder. 4-voice polyphony. Hardware pots select which sample slot each button triggers (range skips empty slots). Click the module title for the MultiSample editor.</p><img src="'+s+'" alt="multi-sample-player module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>gate1</strong></td><td>Triggers the sample assigned to voice 1. Connect from Button, Sequencer, or MIDIIn.</td></tr><tr><td><strong>gate2</strong></td><td>Triggers voice 2.</td></tr><tr><td><strong>gate3</strong></td><td>Triggers voice 3.</td></tr><tr><td><strong>gate4</strong></td><td>Triggers voice 4.</td></tr><tr><td><strong>pitch1</strong></td><td>Playback pitch for voice 1. 1.0 = original, 0.5 = octave down, 2.0 = octave up.</td></tr><tr><td><strong>pitch2</strong></td><td>Playback pitch for voice 2.</td></tr><tr><td><strong>pitch3</strong></td><td>Playback pitch for voice 3.</td></tr><tr><td><strong>pitch4</strong></td><td>Playback pitch for voice 4.</td></tr><tr><td><strong>bank_select</strong></td><td>Selects the active bank of 4 slots (0-3). Connect from Pot or Sequencer to switch sets.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>mixL</strong> (audio)</td><td>Stereo mix of all voices, left.</td></tr><tr><td><strong>mixR</strong> (audio)</td><td>Stereo mix right.</td></tr><tr><td><strong>auxL</strong> (audio)</td><td>Auxiliary send left. Level set by aux_send param.</td></tr><tr><td><strong>auxR</strong> (audio)</td><td>Auxiliary send right.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Upload a folder of related sounds via the MultiSample editor, then trigger with buttons or a Sequencer. Use bank_select to switch between 4 groups of 4 samples during performance. Modulate pitch from an LFO for tape-wobble effects.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const g=e(d,[["render",i]]);export{m as __pageData,g as default};
